import type { LucideIcon } from "lucide-react";

import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";

export function StatCard({
  label,
  value,
  accent,
  icon: Icon,
}: {
  label: string;
  value: string;
  accent?: "neutral" | "positive" | "negative" | "info";
  icon: LucideIcon;
}) {
  return (
    <Card className="p-5">
      <div className="flex items-start justify-between gap-4">
        <div>
          <p className="text-sm text-muted-foreground">{label}</p>
          <p className="mt-3 text-2xl font-semibold tracking-tight text-foreground">
            {value}
          </p>
        </div>
        <div
          className={cn(
            "flex h-12 w-12 items-center justify-center rounded-2xl border",
            accent === "positive" && "border-emerald-500/20 bg-emerald-500/10 text-emerald-300",
            accent === "negative" && "border-red-500/20 bg-red-500/10 text-red-300",
            accent === "info" && "border-sky-500/20 bg-sky-500/10 text-sky-300",
            (!accent || accent === "neutral") &&
              "border-white/10 bg-white/5 text-foreground",
          )}
        >
          <Icon className="h-5 w-5" />
        </div>
      </div>
      {accent === "info" && (
        <Badge className="mt-4" variant="info">
          Model tracked
        </Badge>
      )}
    </Card>
  );
}
